import {Component} from '@angular/core';
import {FormGroup, FormControl} from '@angular/forms';
import {ReactiveFormsModule} from '@angular/forms';

@Component({
  selector: 'app-root',
  template: `
    <form [formGroup]="profileForm" (ngSubmit)="handleSubmit()">
      <input type="text" formControlName="name" />
      <input type="email" formControlName="email" />
      <button type="submit">Submit</button>
    </form>

    <h2>Profile Form</h2>
    <p>Name: {{ profileForm.value.name }}</p>
    <p>Email: {{ profileForm.value.email }}</p>
  `,
  imports: [ReactiveFormsModule],
})
export class App {
  profileForm = new FormGroup({
    name: new FormControl(''),
    email: new FormControl(''),
  });

  handleSubmit() {
    alert(this.profileForm.value.name + ' | ' + this.profileForm.value.email);
  }
}

import {Component, signal} from '@angular/core';

@Component({
  selector: 'app-root',
  template: `
    <div class="user-profile">
      <h1>User Dashboard</h1>
      <div class="status-indicator" [class]="userStatus()">
        <span class="status-dot"></span>
        Status: {{ userStatus() }}
      </div>

      <div class="status-controls">
        <button (click)="goOnline()" [disabled]="userStatus() === 'online'">Go Online</button>
        <button (click)="goOffline()" [disabled]="userStatus() === 'offline'">Go Offline</button>
        <button (click)="toggleStatus()" class="toggle-btn">Toggle Status</button>
      </div>
    </div>
  `,
  styleUrl: './app.css',
})
export class App {
  userStatus = signal<'online' | 'offline'>('offline');

  goOnline() {
    this.userStatus.set('online');
  }

  goOffline() {
    this.userStatus.set('offline');
  }

  toggleStatus() {
    this.userStatus.update((current) => (current === 'online' ? 'offline' : 'online'));
  }
}

import {Component, signal} from '@angular/core';
import {ProductCard} from './product-card';

@Component({
  selector: 'app-root',
  imports: [ProductCard],
  template: `
    <div class="shopping-app">
      <h1>Input Signals Demo</h1>

      <div class="demo-section">
        <h2>Signal Inputs (Parent → Child)</h2>
        <p>Data flows down from parent to child via signal inputs:</p>

        <product-card
          [name]="productName()"
          [price]="productPrice()"
          [available]="productAvailable()"
        />

        <div class="controls">
          <button (click)="updateProduct()">Update Product Data</button>
          <button (click)="toggleAvailability()">Toggle Availability</button>
        </div>
      </div>
    </div>
  `,
  styleUrl: './app.css',
})
export class App {
  // Signal inputs data
  productName = signal('Demo Product');
  productPrice = signal(99);
  productAvailable = signal(true);

  updateProduct() {
    this.productName.set(`Product ${Math.floor(Math.random() * 100)}`);
    this.productPrice.set(Math.floor(Math.random() * 500) + 50);
  }

  toggleAvailability() {
    this.productAvailable.set(!this.productAvailable());
  }
}

import {Component, DestroyRef, inject, input, signal} from '@angular/core';

@Component({
  selector: 'cart-summary',
  template: `
    <div class="cart-summary" [style.background]="isAnimating() ? '#e8f5e8' : ''">
      <h3>Cart Summary {{ isAnimating() ? '🎉' : '' }}</h3>
      <p>Items: {{ itemCount() }}</p>
      <p>Total: \${{ total() }}</p>
      @if (isAnimating()) {
        <p style="color: green; font-weight: bold;">Processing checkout...</p>
      }
    </div>
  `,
  styleUrl: './app.css',
})
export class CartSummary {
  itemCount = input.required<number>();
  total = input.required<number>();

  isAnimating = signal(false);

  private timeoutId?: ReturnType<typeof setTimeout>;
  private destroyRef = inject(DestroyRef);

  // Public method for parent interaction
  initiateCheckout() {
    this.isAnimating.set(true);
    this.timeoutId = setTimeout(() => this.isAnimating.set(false), 2000);
    this.destroyRef.onDestroy(() => clearTimeout(this.timeoutId));
  }
}

import {Component, input, signal} from '@angular/core';

@Component({
  selector: 'product-card',
  template: `
    <div class="product-card" #cardElement>
      <h3 #productTitle>{{ name() }}</h3>
      <p class="price">\${{ price() }}</p>
      <p class="description">{{ description() }}</p>
      <div class="actions">
        <button (click)="toggleDetails()">
          @if (showDetails()) {
            Hide
          } @else {
            Show
          }
          Details
        </button>
      </div>
      @if (showDetails()) {
        <div class="details">
          <p>Product ID: {{ productId() }}</p>
          <p>Category: {{ category() }}</p>
        </div>
      }
    </div>
  `,
  styleUrl: './app.css',
})
export class ProductCard {
  name = input.required();
  price = input.required<number>();
  description = input('');
  available = input(true);
  productId = input('');
  category = input('');

  showDetails = signal(false);

  toggleDetails() {
    this.showDetails.set(!this.showDetails());
  }

  // Public methods for parent interaction
  highlight() {
    this.showDetails.set(true);
  }
}

@use '../../../shared/object-tree-explorer/prop-action-btn';

.tag-active,
.tag-inactive {
  border-radius: 1rem;
  padding: 0.15rem 0.5rem;
  border: 1px solid;
}

.tag-active {
  border-color: var(--green-03);
}

.tag-inactive {
  border-color: var(--red-06);
}

button {
  width: 16px;
  height: 16px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  vertical-align: middle;
  color: var(--quaternary-contrast);

  &:not([disabled]):hover {
    color: var(--primary-contrast);
  }

  &[disabled] {
    cursor: default;
    color: var(--quinary-contrast);
  }

  mat-icon {
    font-size: 14px;
    width: 14px;
    height: 14px;

    &.view-source {
      font-size: 16px;
      width: 16px;
      height: 16px;
    }
  }
}

td {
  width: 100%;
}

ng-object-tree-explorer {
  --ote-padding: 0rem;
}

@if (shouldRun) {
  <div class="example-container" [class.example-is-mobile]="isMobile()">
    <mat-toolbar class="example-toolbar">
      <button matIconButton (click)="snav.toggle()"><mat-icon>menu</mat-icon></button>
      <h1 class="example-app-name">Responsive App</h1>
    </mat-toolbar>

    <mat-sidenav-container class="example-sidenav-container"
                          [style.marginTop.px]="isMobile() ? 56 : 0">
      <mat-sidenav #snav [mode]="isMobile() ? 'over' : 'side'"
                  [fixedInViewport]="isMobile()" fixedTopGap="56">
        <mat-nav-list>
          @for (nav of fillerNav; track nav) {
            <a mat-list-item>{{nav}}</a>
          }
        </mat-nav-list>
      </mat-sidenav>

      <mat-sidenav-content>
        @for (content of fillerContent; track content) {
    <p>{{content}}</p>
  }
      </mat-sidenav-content>
    </mat-sidenav-container>
  </div>
} @else {
  <div>Please open on Stackblitz to see result</div>
}

@import "./card-content";
@import "./card-content.md.vars";

// Material Design Card Content
// --------------------------------------------------

.card-content-md {
  @include padding($card-md-padding-top, $card-md-padding-end, $card-md-padding-bottom, $card-md-padding-start);

  font-size: $card-md-font-size;

  line-height: $card-md-line-height;

  h1 {
    @include margin(0, 0, 2px);

    font-size: dynamic-font(24px);
    font-weight: normal;
  }

  h2 {
    @include margin(2px, 0);

    font-size: dynamic-font(16px);
    font-weight: normal;
  }

  h3,
  h4,
  h5,
  h6 {
    @include margin(2px, 0);

    font-size: dynamic-font(14px);
    font-weight: normal;
  }

  p {
    @include margin(0, 0, 2px);

    font-size: dynamic-font(14px);
    font-weight: normal;

    line-height: 1.5;
  }
}

ion-card-header + .card-content-md {
  padding-top: 0;
}
